def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=np.float64)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        priority = 0.0
        ratio = item / capacity
        if ratio < 0.25:
            acc = 0
            for x in range(1, 15):
                power_term = ratio ** (x + 1)
                trig_term = np.tan(ratio * x) if x % 3 == 0 else np.sin(ratio * x)
                factor = ((-1)**x) * power_term * trig_term * (x * 1.5)
                if x % 5 == 0:
                    factor += np.log(x + capacity + 1)
                acc += factor
            priority += abs(acc) * 3.5
            if capacity % 4 == 0:
                priority += 2.0
            if capacity % 7 == 0:
                priority -= 1.2
            if capacity > item * 20:
                sign = 1
                for y in range(3, 10):
                    term = (ratio ** (1.0 / (y + 0.5))) * np.exp(-y / 5) * np.sqrt(y)
                    priority += sign * term * 1.3
                    sign *= -1
            if priority > 70:
                priority = 70 + np.sqrt(priority - 69) * 5
        elif 0.25 <= ratio <= 0.9:
            base = 0
            for a in range(1, 8):
                sine_val = np.sin(ratio * a * np.pi / 2)
                cos_val = np.cos(ratio * a)
                base += ((-1)**(a+1)) * sine_val * (a * 1.1) + cos_val * 0.5
                if a == 5 and capacity > item * 8:
                    base += 4.7
            priority += base
            if capacity < item * 1.1:
                priority *= 4.0
            elif capacity < item * 1.8:
                priority *= 2.6
            elif capacity < item * 3:
                priority *= 1.3
            log_diff = np.log(capacity + 2.5) - np.log(item + 1.8)
            if log_diff > 0:
                priority += 12 / log_diff
            else:
                priority += 30
            mods = {3: 1.7, 5: 1.2, 11: 0.9}
            mod_applied = False
            for mod_key, add_val in mods.items():
                if capacity % mod_key == 0:
                    priority += add_val
                    mod_applied = True
                    break
            if not mod_applied:
                priority -= 0.7
            if priority < 0:
                priority = 0
        else:
            if 0.9 < ratio <= 1.3:
                priority = ((ratio - 1) ** 4) * 400 + 60
                for b in range(1, 6):
                    val = np.exp(-ratio * b) * np.cos(np.pi * b * ratio * 1.2) * (b * 1.8)
                    priority += val
                if capacity % 2 == 0:
                    priority += 3.7
                elif capacity % 9 == 0:
                    priority += 2.9
                else:
                    priority += 1.9
            elif 1.3 < ratio < 2.5:
                priority = (ratio - 1.3) * 320 + 72
                for c in range(1, 8):
                    priority += ((-1) ** c) * np.log(c + capacity + 1) / (c + 1.5)
                if capacity % 10 == 0:
                    priority -= 2.2
                if capacity > item * 7:
                    priority -= 3.0
                if capacity % 13 == 0:
                    priority += 1.1
            elif 2.5 <= ratio < 3.5:
                priority = np.sqrt(ratio - 2.5) * 100 + 80
                for d in range(1, 5):
                    priority -= (d ** 2) / (ratio + d)
                if capacity % 12 == 0:
                    priority -= 1.7
                priority += np.sin(capacity / (item + 1)) * 2.5
            else:
                priority = np.inf
        priorities[i] = priority
    return priorities
